 44→static def findNodeModules(baseDir) {
 45→  def basePath = baseDir.toPath().normalize()
 46→  // Node's module resolution algorithm searches up to the root directory,
 47→  // after which the base path will be null
 48→  while (basePath) {
 49→    def nodeModulesPath = Paths.get(basePath.toString(), "node_modules")
 50→    def reactNativePath = Paths.get(nodeModulesPath.toString(), "react-native")
 51→    if (nodeModulesPath.toFile().exists() && reactNativePath.toFile().exists()) {
 52→      return nodeModulesPath.toString()
 53→    }
 54→    basePath = basePath.getParent()
 55→  }
 56→  throw new GradleException("React-Native-Skia: Failed to find node_modules/ path!")
 57→}
