289→def localBuildDir = buildDir
290→def headersConfiguration = configurations.extractHeaders
291→def jniConfiguration = configurations.extractJNI
292→
293→task extractAARHeaders {
294→    doLast {
295→        headersConfiguration.files.each { file ->
296→            def absFile = file.absoluteFile
297→            project.copy {
298→                from project.zipTree(absFile)
299→                into "${localBuildDir}/${absFile.name}"
300→                include "**/*.h"
301→            }
302→        }
303→    }
304→}
305→
306→task extractJNIFiles {
307→    doLast {
308→        jniConfiguration.files.each { file ->
309→            def absFile = file.absoluteFile
310→            project.copy {
311→                from project.zipTree(absFile)
312→                into "${localBuildDir}/${absFile.name}"
313→                include "jni/**/*"
314→            }
315→        }
316→    }
317→}
318→
319→extractJNIFiles.mustRunAfter extractAARHeaders
320→
321→if (ENABLE_PREFAB) {
322→    // Package all the cpp code in a flattened directory structure
323→    task prepareHeaders(type: Copy) {
324→        from("../cpp")
325→        from("./cpp")
326→        into "${project.buildDir}/headers/rnskia/react-native-skia"
327→        includeEmptyDirs = false
328→        include "**/*.h"
329→        eachFile {
330→            String path = it.path
331→
332→            if (path.contains("api/third_party")) {
333→                // Skip flattening third_party dir
334→                path = path.substring("api/".length())
335→            } else if (path.contains("skia/include") || path.contains("skia/modules") || path.contains("skia/src")) {
336→                // Skip flattening Skia dir
337→                path = path.substring("skia/".length())
338→            } else if (path.startsWith("dawn/include/")) {
339→                // Flatten dawn/include/dawn and dawn/include/webgpu
340→                path = path.substring("dawn/include/".length())
341→            } else {
342→                // flatten anything else
343→                path = path.substring(path.lastIndexOf("/") + 1)
344→            }
345→            it.path = path
346→        }
347→    }
348→    preBuild.dependsOn(prepareHeaders)
349→}
350→
351→def nativeBuildDependsOn(dependsOnTask, variant) {
352→  def buildTasks = tasks.findAll({ task ->
353→      !task.name.contains("Clean") && (task.name.contains("externalNative") || task.name.contains("CMake")) })
354→  if (variant != null) {
355→    buildTasks = buildTasks.findAll({ task -> task.name.contains(variant) })
356→  }
357→  buildTasks.forEach { task -> task.dependsOn(dependsOnTask) }
358→}
359→
360→afterEvaluate {
361→  nativeBuildDependsOn(extractAARHeaders, null)
362→  nativeBuildDependsOn(extractJNIFiles, null)
363→}
