117→const QUICK_ACTIONS = [
118→  {key: 'all', label: 'All'},
119→  {key: 'journal', label: 'Journals'},
120→  {key: 'canvas', label: 'Canvas'},
121→  {key: 'freedom_wall', label: 'Freedom Wall'},
122→  {key: 'universe', label: 'Universe'},
123→] as const;
