  1→import {apiRequest} from './apiClient';
  2→import type {CursorPage, JournalItem} from './mobileApi';
  3→
  4→export type JournalComment = {
  5→  id: string;
  6→  comment?: string;
  7→  created_at?: string;
  8→  parent_id?: string | null;
  9→  post_id?: string;
 10→  user_id?: string;
 11→  users?: {
 12→    id?: string;
 13→    name?: string;
 14→    image_url?: string;
 15→    badge?: string;
 16→  } | null;
 17→  reply_count?: number;
 18→};
 19→
 20→type NotificationSource = 'journal' | 'opinion' | string;
 21→
 22→const authHeaders = (token?: string): Record<string, string> => {
 23→  if (!token) {
 24→    return {};
 25→  }
 26→  return {Authorization: `Bearer ${token}`};
 27→};
 28→
 29→export const socialApi = {
 30→  async likeJournal(
 31→    token: string,
 32→    payload: {
 33→      journalId: string;
 34→      receiverId?: string;
 35→      senderImageUrl?: string;
 36→      sendername?: string;
 37→      senderEmail?: string;
 38→    },
 39→  ): Promise<{message?: string}> {
 40→    return apiRequest<{message?: string}>('/like', {
 41→      method: 'POST',
 42→      headers: {
 43→        ...authHeaders(token),
 44→        'Content-Type': 'application/json',
 45→      },
 46→      body: JSON.stringify(payload),
 47→    });
 48→  },
 49→
 50→  async addComment(
 51→    token: string,
 52→    payload: {comments: string; postId: string; receiverId?: string; parentId?: string},
 53→  ): Promise<{message?: string}> {
 54→    return apiRequest<{message?: string}>('/addComment', {
 55→      method: 'POST',
 56→      headers: {
 57→        ...authHeaders(token),
 58→        'Content-Type': 'application/json',
 59→      },
 60→      body: JSON.stringify(payload),
 61→    });
 62→  },
 63→
 64→  async getComments(
 65→    postId: string,
 66→    cursor: string | null = null,
 67→    limit = 20,
 68→  ): Promise<{comments: JournalComment[]; hasMore?: boolean}> {
 69→    const params = new URLSearchParams();
 70→    params.set('postId', postId);
 71→    params.set('limit', String(limit));
 72→    if (cursor) {
 73→      params.set('before', cursor);
 74→    }
 75→
 76→    return apiRequest<{comments: JournalComment[]; hasMore?: boolean}>(
 77→      `/getComments?${params.toString()}`,
 78→      {method: 'GET'},
 79→    );
 80→  },
 81→
 82→  async getReplies(
 83→    postId: string,
 84→    parentId: string,
 85→    limit = 20,
 86→  ): Promise<{comments: JournalComment[]; hasMore?: boolean}> {
 87→    const params = new URLSearchParams();
 88→    params.set('postId', postId);
 89→    params.set('parentId', parentId);
 90→    params.set('limit', String(limit));
 91→
 92→    return apiRequest<{comments: JournalComment[]; hasMore?: boolean}>(
 93→      `/getComments?${params.toString()}`,
 94→      {method: 'GET'},
 95→    );
 96→  },
 97→
 98→  async toggleBookmark(
 99→    token: string,
100→    payload: {journalId: string},
101→  ): Promise<{message?: string}> {
102→    return apiRequest<{message?: string}>('/addBoorkmark', {
103→      method: 'POST',
104→      headers: {
105→        ...authHeaders(token),
106→        'Content-Type': 'application/json',
107→      },
108→      body: JSON.stringify(payload),
109→    });
110→  },
111→
112→  async getBookmarks(
113→    token: string,
114→    userId: string,
115→    cursor: string | null = null,
116→    limit = 10,
117→  ): Promise<CursorPage<JournalItem>> {
118→    const params = new URLSearchParams();
119→    params.set('userId', userId);
120→    params.set('limit', String(limit));
121→    if (cursor) {
122→      params.set('before', cursor);
123→    }
124→
125→    return apiRequest<CursorPage<JournalItem>>(`/getBookmarks?${params.toString()}`, {
126→      method: 'GET',
127→      headers: {
128→        ...authHeaders(token),
129→      },
130→    });
131→  },
132→
133→  async getNotificationsCount(
134→    token: string,
135→    userId: string,
136→  ): Promise<{count?: number}> {
137→    const params = new URLSearchParams();
138→    params.set('userId', userId);
139→    return apiRequest<{count?: number}>(`/getCountNotifications?${params.toString()}`, {
140→      method: 'GET',
141→      headers: {
142→        ...authHeaders(token),
143→      },
144→    });
145→  },
146→
147→  async markNotificationRead(
148→    token: string,
149→    notifId: string,
150→    source?: NotificationSource,
151→  ): Promise<{message?: string}> {
152→    return apiRequest<{message?: string}>('/readNotification', {
153→      method: 'POST',
154→      headers: {
155→        ...authHeaders(token),
156→        'Content-Type': 'application/json',
157→      },
158→      body: JSON.stringify({notifId, source}),
159→    });
160→  },
161→
162→  async deleteNotification(
163→    token: string,
164→    notifId: string,
165→    source?: NotificationSource,
166→  ): Promise<{message?: string}> {
167→    const suffix = source
168→      ? `/deleteNotification/${encodeURIComponent(notifId)}?source=${encodeURIComponent(source)}`
169→      : `/deleteNotification/${encodeURIComponent(notifId)}`;
170→
171→    return apiRequest<{message?: string}>(suffix, {
172→      method: 'DELETE',
173→      headers: {
174→        ...authHeaders(token),
175→      },
176→    });
177→  },
178→
179→  async getUnreadNotifications(
180→    token: string,
181→    cursor: string | null = null,
182→    limit = 10,
183→  ): Promise<CursorPage<unknown>> {
184→    const params = new URLSearchParams();
185→    params.set('limit', String(limit));
186→    if (cursor) {
187→      params.set('before', cursor);
188→    }
189→
190→    return apiRequest<CursorPage<unknown>>(`/getUnreadNotification?${params.toString()}`, {
191→      method: 'GET',
192→      headers: {
193→        ...authHeaders(token),
194→      },
195→    });
196→  },
197→
198→  async toggleReaction(
199→    token: string,
200→    payload: {
201→      journalId: string;
202→      receiverId: string;
203→      reactionType: string;
204→    },
205→  ): Promise<{message?: string}> {
206→    return apiRequest<{message?: string}>('/reaction', {
207→      method: 'POST',
208→      headers: {
209→        ...authHeaders(token),
210→        'Content-Type': 'application/json',
211→      },
212→      body: JSON.stringify(payload),
213→    });
214→  },
215→
216→  async createRepost(
217→    token: string,
218→    payload: {sourceJournalId: string; caption?: string},
219→  ): Promise<{message?: string}> {
220→    return apiRequest<{message?: string}>('/repost', {
221→      method: 'POST',
222→      headers: {
223→        ...authHeaders(token),
224→        'Content-Type': 'application/json',
225→      },
226→      body: JSON.stringify(payload),
227→    });
228→  },
229→};
